  export const TOP_10_READING_FONTS = READING_FONTS.filter(f => f.top10);

  /** Inject a Google Fonts <link> for the given family param, only once. */
  export function ensureReadingFontLoaded(gfontParam: string) {
    if (!gfontParam) return;
    if (typeof document === 'undefined') return;
    const id = `gfont-rd-${gfontParam.replace(/[^a-zA-Z0-9]/g, '-')}`;
    if (document.getElementById(id)) return;
    const link = document.createElement('link');
    link.id = id;
    link.rel = 'stylesheet';
    link.href = `https://fonts.googleapis.com/css2?family=${gfontParam}&display=swap`;
    document.head.appendChild(link);
  }

  export function getReadingFontById(id: string | undefined | null): ReadingFont | null {
    if (!id) return null;
    return READING_FONTS.find(f => f.id === id) || null;
  }
  